body.script:
(function(){
  var c=document.getElementById('bgCanvas'),ctx=c.getContext('2d');
  function res(){c.width=window.innerWidth;c.height=window.innerHeight}
  res();window.onresize=res;
  var pts=[];for(var i=0;i<50;i++)pts.push({x:Math.random()*c.width,y:Math.random()*c.height,vx:(Math.random()-.5)*.5,vy:(Math.random()-.5)*.5});
  function draw(){
    ctx.clearRect(0,0,c.width,c.height);
    ctx.fillStyle='rgba(0,0,255,0.5)';
    pts.forEach(p=>{
      ctx.beginPath();ctx.arc(p.x,p.y,2,0,Math.PI*2);ctx.fill();
      p.x+=p.vx;p.y+=p.vy;
      if(p.x<0||p.x>c.width)p.vx*=-1;if(p.y<0||p.y>c.height)p.vy*=-1;
    });
    requestAnimationFrame(draw);
  }
  draw();
})();

const FOLDERS=[
  {id:'games',name:'Games',color:'#3b82f6',projects:[
    {name:'SN GN Math 2026',desc:'USE ME TO PLAY GAMES! Better organization and settings.',url:'https://cdn.jsdelivr.net/gh/storynetwork-camzzz/Story-Network-GN-Math-2026@latest/index.html',accent:'#3b82f6'},
    {name:'SN Smash Bros',desc:'A Smash Bros inspired fighting game.',url:'https://cdn.jsdelivr.net/gh/storynetwork-camzzz/SN-Smash-Bros@latest/index.html',accent:'#ff4444'}
  ]},
  {id:'utilities',name:'Utilities',color:'#4facfe',projects:[
    {name:'SN Tools',desc:'Useful tools for developers.',url:'https://cdn.jsdelivr.net/gh/storynetwork-camzzz/SN-Tools@latest/index.html',accent:'#4facfe'}
  ]}
];

function renderFolders(){
  const grid=document.getElementById('folder-grid');
  FOLDERS.forEach(f=>{
    const card=document.createElement('div');
    card.className='folder-card';
    card.innerHTML=`<h3 style="color:${f.color}">${f.name}</h3><p style="font-size:0.8rem;color:#4a4a88;margin-top:5px">${f.projects.length} Projects</p><button class="btn" style="background:${f.color}">Open</button>`;
    card.onclick=()=>openFolder(f);
    grid.appendChild(card);
  });
}

function openFolder(f){
  document.getElementById('view-home').style.display='none';
  document.getElementById('view-folder').style.display='block';
  document.getElementById('back-btn').classList.add('visible');
  document.getElementById('fv-title').textContent=f.name;
  const pg=document.getElementById('project-grid');
  pg.innerHTML='';
  f.projects.forEach(p=>{
    const card=document.createElement('div');
    card.className='card';
    card.innerHTML=`<h3>${p.name}</h3><p style="font-size:0.8rem;color:#4a4a88;margin:10px 0">${p.desc}</p><button class="btn" style="background:${p.accent}">Launch</button>`;
    card.onclick=()=>openModal(p);
    pg.appendChild(card);
  });
}

function goHome(){
  document.getElementById('view-home').style.display='block';
  document.getElementById('view-folder').style.display='none';
  document.getElementById('back-btn').classList.remove('visible');
}

let active=null;
function openModal(p){active=p;document.getElementById('modal-name').textContent=p.name;document.getElementById('modal-desc').textContent=p.desc;document.getElementById('overlay').classList.add('open')}
function closeModal(){document.getElementById('overlay').classList.remove('open')}

function doLaunch(){
  if(!active)return;
  const loader=document.getElementById('loadscreen');
  const frame=document.getElementById('appframe');
  loader.style.display='flex';
  frame.style.display='block';
  frame.src=active.url;
  frame.onload=()=>loader.style.display='none';
  closeModal();
}

renderFolders();
